import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testPrint() throws IOException {
        // Given
        CSVFormat csvFormat = createCSVFormat();
        Object value = "test";
        Appendable out = new StringWriter();
        boolean newRecord = true;

        // When
        csvFormat.print(value, out, newRecord);

        // Then
        assertEquals("test\r\n", out.toString());
    }

    private CSVFormat createCSVFormat() {
        try {
            return (CSVFormat) CSVFormat.class.getDeclaredConstructor(char.class, Character.class, QuoteMode.class,
                    Character.class, Character.class, boolean.class, boolean.class, String.class, String.class,
                    Object[].class, String[].class, boolean.class, boolean.class, boolean.class, boolean.class,
                    boolean.class).newInstance(',', '"', null, null, null, false, true, "\r\n", null, null, null, false,
                    false, false, false, false);
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }

